// JS uses UTF-16 encoding, so characters outside the BMP (U+10000+) count as
// 2 code units (surrogate pair), matching how JS .length works.
func jsStringLength(s string) int {
	n := 0
	for _, r := range s {
		if r >= 0x10000 {
			n += 2 // surrogate pair
		} else {
			n += 1
		}
	}
	return n
}

