// --- Go helper functions ---

func boolStr(b bool) string {
	if b {
		return "true"
	}
	return "false"
}

func chatBubbleClass(role string) string {
	if role == "User" {
		return "chat-bubble-user-msg"
	}
	return "chat-bubble-assistant-msg"
}

// hasEarlierNonFollowup checks if there's a non-followup execution before currentIdx.
// Used to deduplicate the task prompt: only the first non-followup shows the user bubble.
func hasEarlierNonFollowup(execs []models.Execution, currentIdx int) bool {
	for j := 0; j < currentIdx; j++ {
		if !execs[j].IsFollowup {
			return true
		}
	}
	return false
}

// chatUserContent returns the display text for a user message in a chat thread.
// For the first non-followup execution in a task context, it shows the task prompt.
// For follow-up messages or when there's no task, it shows PromptSent.
func chatUserContent(exec models.Execution, task *models.Task, execs []models.Execution, idx int) string {
	if task != nil && !exec.IsFollowup && !hasEarlierNonFollowup(execs, idx) {
		return task.Prompt
	}
	return exec.PromptSent
}

// IsImageMediaType checks if a media type is an image type.
func IsImageMediaType(mediaType string) bool {
	return strings.HasPrefix(mediaType, "image/")
}

// Regex patterns for cleaning action markers from display content (server-side).
var (
	reCreateTask  = regexp.MustCompile(`(?s)\[CREATE_TASK\].*?\[/CREATE_TASK\]`)
	reEditTask    = regexp.MustCompile(`(?s)\[EDIT_TASK\].*?\[/EDIT_TASK\]`)
	reExecTasks   = regexp.MustCompile(`(?s)\[EXECUTE_TASKS\].*?\[/EXECUTE_TASKS\]`)
	reStatus      = regexp.MustCompile(`\[STATUS:\s*(?:SUCCESS|FAILED|NEEDS_FOLLOWUP)(?:\s*\|[^\]]*?)?\]`)
	reUsingTool   = regexp.MustCompile(`\[Using tool:\s*[^\]]+\]`)
	reToolBlock   = regexp.MustCompile(`(?s)\[Tool\s+\S+\s+(?:done|error)\]\n?[\s\S]*?\n?\[/Tool\]\n?`)
	reToolDone    = regexp.MustCompile(`\[Tool\s+\S+\s+(?:done|error):[^\]]*\](?:\n)?`)
	reProtocolArt = regexp.MustCompile(`(?m)^[}\s{]*(?:to=)?multi_tool_use\.\S+[^\n]*$`)
	reThinking    = regexp.MustCompile(`(?s)\n?\[Thinking\][\s\S]*?(?:\[/Thinking\]\n?|$)`)
	reExcessLines = regexp.MustCompile(`\n{3,}`)
)

// CleanDisplayContent strips action markers from chat content for display.
func CleanDisplayContent(text string) string {
	if text == "" {
		return text
	}
	text = reCreateTask.ReplaceAllString(text, "")
	text = reEditTask.ReplaceAllString(text, "")
	text = reExecTasks.ReplaceAllString(text, "")
	text = reStatus.ReplaceAllString(text, "")
	text = reUsingTool.ReplaceAllString(text, "")
	text = reToolBlock.ReplaceAllString(text, "")
	text = reToolDone.ReplaceAllString(text, "")
	text = reProtocolArt.ReplaceAllString(text, "")

	// Strip thinking blocks, but if that would leave the text empty,
	// extract the thinking content as the display text (the model put
	// its entire response inside a thinking block).
	cleaned := reThinking.ReplaceAllString(text, "")
	if strings.TrimSpace(cleaned) == "" && strings.TrimSpace(text) != "" {
		text = extractThinkingContent(text)
	} else {
		text = cleaned
	}

	text = DedupTaskSummaries(text)
	text = reExcessLines.ReplaceAllString(text, "\n\n")
	return strings.TrimSpace(text)
}

// extractThinkingContent pulls the text from inside [Thinking]...[/Thinking]
// blocks (or unclosed [Thinking]... to end of string). Used as a fallback when
// the model's entire response is inside thinking blocks.
// When thinking blocks are unclosed (no [/Thinking] marker — common with Claude CLI
// extended thinking), the first [Thinking] captures everything to end-of-string,
// which may include subsequent [Thinking] markers as raw text. We strip these
// embedded markers so the extracted content is clean for display.
func extractThinkingContent(text string) string {
	var parts []string
	for {
		start := strings.Index(text, "[Thinking]")
		if start == -1 {
			break
		}
		after := text[start+len("[Thinking]"):]
		end := strings.Index(after, "[/Thinking]")
		var content string
		if end != -1 {
			content = after[:end]
			text = after[end+len("[/Thinking]"):]
		} else {
			content = after
			text = ""
		}
		content = strings.TrimSpace(content)
		if content != "" {
			parts = append(parts, content)
		}
	}
	result := strings.Join(parts, "\n\n")
	// Strip any embedded [Thinking]/[/Thinking] markers that ended up in
	// the extracted content (happens when thinking blocks are unclosed and
	// the first block captures everything including subsequent markers).
	result = strings.ReplaceAll(result, "[Thinking]", "")
	result = strings.ReplaceAll(result, "[/Thinking]", "")
	return strings.TrimSpace(result)
}

// DedupTaskSummaries removes duplicate task summary blocks.
func DedupTaskSummaries(text string) string {
	for _, marker := range []string{"\n---\nCreated ", "\n---\nEdited "} {
		firstIdx := strings.Index(text, marker)
		lastIdx := strings.LastIndex(text, marker)
		if firstIdx != -1 && firstIdx != lastIdx {
			text = text[:firstIdx] + text[lastIdx:]
		}
	}
	return text
}

